import { useState, useEffect } from "react";
import { JOBS, APPS_SEED, INITIAL_USERS } from "./data/jobs";
import { injectStyles }             from "./utils/styles";
import { useToast }                 from "./hooks/useToast";

import Navbar           from "./components/Navbar";
import Footer           from "./components/Footer";
import { Toast }        from "./components/UI";

import AuthPage         from "./pages/AuthPage";
import HomePage         from "./pages/HomePage";
import JobsPage         from "./pages/JobsPage";
import JobDetailPage    from "./pages/JobDetailPage";
import AboutPage        from "./pages/AboutPage";
import ContactPage      from "./pages/ContactPage";
import MyAppsPage       from "./pages/MyAppsPage";
import AdminDashboard   from "./pages/AdminDashboard";
import ProfilePage      from "./pages/ProfilePage";

const API_URL = "http://localhost:5000/api";

export default function App() {
  useEffect(() => injectStyles(), []);

  const [page,     setPage]     = useState("home");
  const [jobId,    setJobId]    = useState(null);
  const [authMode, setAuthMode] = useState(null); 
  const [user,     setUser]     = useState(null);
  const [jobs,     setJobs]     = useState([]);
  const [apps,     setApps]     = useState([]);
  const [users,    setUsers]    = useState([]);
  const [loading,  setLoading]  = useState(true);
  const toast = useToast();

  // ─── Session Persistence & Data Loading ───
  useEffect(() => {
    const saved = localStorage.getItem("catalyst_user");
    if (saved) setUser(JSON.parse(saved));

    const fetchData = async () => {
      try {
        const jRes = await fetch(`${API_URL}/jobs`);
        const jData = await jRes.json();
        setJobs(jData);

        if (saved) {
          const u = JSON.parse(saved);
          const token = localStorage.getItem("catalyst_token");
          const endpoint = u.role === "admin" ? "/apps/all" : "/apps/user";
          const aRes = await fetch(`${API_URL}${endpoint}`, {
            headers: { "Authorization": `Bearer ${token}` }
          });
          const aData = await aRes.json();
          setApps(aData);
        }
      } catch (err) {
        console.error("Fetch error:", err);
      } finally {
        setLoading(false);
      }
    };
    fetchData();
  }, []);

  /* Navigation */
  const nav = (p, id) => {
    setPage(p);
    if (id !== undefined) setJobId(id);
    window.scrollTo({ top: 0, behavior: "smooth" });
  };

  /* Auth */
  const login = (u, token) => { 
    setUser(u); 
    localStorage.setItem("catalyst_user", JSON.stringify(u));
    localStorage.setItem("catalyst_token", token);
    setAuthMode(null); 
    nav(u.role === "admin" ? "admin" : "home"); 
  };
  const logout = () => { 
    setUser(null); 
    localStorage.removeItem("catalyst_user");
    localStorage.removeItem("catalyst_token");
    nav("home"); 
    toast.add("Signed out.", "success"); 
  };
  const updateProfile = data => {
    setUser(prev => ({ ...prev, ...data }));
    setUsers(us => us.map(u => u.email === (user?.email || data.email) ? { ...u, ...data } : u));
  };

  /* User Management (Admin) */
  const updateUserStatus = (id, status) => {
    setUsers(us => us.map(u => u.id === id ? { ...u, status } : u));
  };
  const deleteUser = id => {
    setUsers(us => us.filter(u => u.id !== id));
  };
  const resetUserPassword = id => {
    toast.add("Password reset link sent to user email.", "info");
  };

  /* Application submit */
  const apply = async data => {
    const token = localStorage.getItem("catalyst_token");
    try {
      const res = await fetch(`${API_URL}/apps`, {
        method: "POST",
        headers: { "Content-Type": "application/json", "Authorization": `Bearer ${token}` },
        body: JSON.stringify({
          jobId:      data.jobId,
          name:       data.name,
          email:      data.email,
          phone:      data.phone,
          experience: data.exp || "",
          resume_url: data.resume ? (data.resume.name || data.resume) : ""
        })
      });
      const newApp = await res.json();
      setApps(prev => [...prev, newApp]);
      toast.add("Application submitted! 🎉", "success");
      nav("myapps");
    } catch (err) {
      toast.add("Failed to submit application", "error");
    }
  };

  /* Status update (admin) */
  const updateStatus = async (id, status) => {
    const token = localStorage.getItem("catalyst_token");
    const app = apps.find(a => a.id === id);
    const newTl = [...new Set([...(app.timeline || []), status])];
    try {
      await fetch(`${API_URL}/apps/${id}/status`, {
        method: "PUT",
        headers: { "Content-Type": "application/json", "Authorization": `Bearer ${token}` },
        body: JSON.stringify({ status, timeline: newTl })
      });
      setApps(prev => prev.map(x => x.id !== id ? x : { ...x, status, timeline: newTl }));
    } catch (err) {
      toast.add("Failed to update status", "error");
    }
  };

  /* Job CRUD (admin) */
  const addOrUpdateJob = job => setJobs(js => {
    const existing = js.find(x => x.id === job.id);
    return existing ? js.map(x => x.id === job.id ? job : x) : [...js, job];
  });
  const deleteJob = id => setJobs(js => js.filter(j => j.id !== id));

  const selectedJob = jobs.find(j => j.id === jobId);

  /* Full-screen Auth view */
  if (authMode) {
    return (
      <>
        <AuthPage
          mode={authMode}
          onBack={() => setAuthMode(null)}
          onLogin={login}
          toast={toast}
        />
        <Toast items={toast.items} rm={toast.rm} />
      </>
    );
  }

  return (
    <div style={{ minHeight: "100vh", display: "flex", flexDirection: "column" }}>
      <Navbar page={page} nav={nav} user={user} openAuth={m => setAuthMode(m)} doLogout={logout} />

      <div style={{ flex: 1 }}>
        {page === "home"    && <HomePage     jobs={jobs} nav={nav} openAuth={m => setAuthMode(m)} />}
        {page === "jobs"    && <JobsPage     jobs={jobs} nav={nav} />}
        {page === "job"     && <JobDetailPage job={selectedJob} nav={nav} onApply={apply} user={user} openAuth={m => setAuthMode(m)} />}
        {page === "about"   && <AboutPage />}
        {page === "contact" && <ContactPage  toast={toast} />}
        {page === "myapps"  && <MyAppsPage   apps={apps} user={user} />}
        {page === "profile" && <ProfilePage  user={user} onUpdateProfile={updateProfile} toast={toast} />}

        {page === "admin" && user?.role === "admin" && (
          <AdminDashboard
            jobs={jobs} apps={apps} users={users}
            onUpdateStatus={updateStatus}
            onUpdateUserStatus={updateUserStatus}
            onDeleteUser={deleteUser}
            onResetUserPassword={resetUserPassword}
            onAddJob={addOrUpdateJob}
            onDeleteJob={deleteJob}
            toast={toast}
          />
        )}
        {page === "admin" && user?.role !== "admin" && (
          <div style={{ textAlign: "center", padding: 80 }}>
            <div style={{ fontSize: 52 }}>🔒</div>
            <div style={{ fontWeight: 700, fontSize: 20, marginTop: 16 }}>Admin access required</div>
          </div>
        )}
      </div>

      {/* Hidden admin access: click © copyright 5× in footer */}
      <Footer nav={nav} onAdminAccess={() => setAuthMode("admin")} />
      <Toast items={toast.items} rm={toast.rm} />
    </div>
  );
}
